SELECT event_no AS eventNo, event_type AS eventType, payment_order_id AS paymentOrderId, biz_no AS bizNo, event_topic AS eventTopic, downstream_system AS downstreamSystem, publish_status AS publishStatus, publish_status_type AS publishStatusType, retry_count AS retryCount, DATE_FORMAT(last_published_at, '%Y-%m-%d %H:%i:%s') AS lastPublishedAt, DATE_FORMAT(next_retry_at, '%Y-%m-%d %H:%i:%s') AS nextRetryAt, event_payload AS eventPayload, DATE_FORMAT(created_at, '%Y-%m-%d %H:%i:%s') AS createdAt FROM t_payment_event
payment_order_id LIKE CONCAT('%', #{query.paymentOrderId}, '%')
AND event_type = #{query.eventType}
AND publish_status = #{query.publishStatus}
AND downstream_system LIKE CONCAT('%', #{query.downstreamSystem}, '%')
ORDER BY created_at DESC LIMIT #{query.limit} OFFSET #{query.offset}

